func PackageFunctionNames(path string) []string {
    if names, ok := packageFunctionNames[path]; ok {
        return names
    }
    return []string{}
}

func PackageMemberNames(path string) []string {
    if names, ok := packageMemberNames[path]; ok {
        return names
    }
    return []string{}
}

func PackageMemberType(path string, name string) string {
    if names, ok := packageMemberTypes[path]; ok {
        if typ, ok := names[name]; ok {
            return typ
        }
    }
    return ""
}

func MethodNames(receiverType string) []string {
    if names, ok := methodNames[receiverType]; ok {
        return names
    }
    return []string{}
}

func GeneratedStructFieldNames(typeName string) []string {
    if fields, ok := structFieldNames[typeName]; ok {
        return fields
    }
    return []string{}
}

func GeneratedStructFieldType(typeName string, fieldName string) string {
    if fields, ok := structFieldTypes[typeName]; ok {
        if typ, ok := fields[fieldName]; ok {
            return typ
        }
    }
    return ""
}


func PackageFuncPrototype(path string, name string) base.Option[FuncInfo] {
    if sigs, ok := packageFunctionSigs[path]; ok {
        if sig, ok := sigs[name]; ok {
            return base.Some[FuncInfo]{Value0: sig.Prototype()}
        }
    }
    return base.None[FuncInfo]{}
}

func PackageFuncSig(path string, name string, argCount int) base.Option[FuncInfo] {
    if sigs, ok := packageFunctionSigs[path]; ok {
        if sig, ok := sigs[name]; ok {
            if value, ok := sig.Exact(argCount); ok {
                return base.Some[FuncInfo]{Value0: value}
            }
            return base.None[FuncInfo]{}
        }
    }
    return base.None[FuncInfo]{}
}

func MethodPrototype(receiverType string, name string) base.Option[FuncInfo] {
    if sigs, ok := methodSigs[receiverType]; ok {
        if sig, ok := sigs[name]; ok {
            return base.Some[FuncInfo]{Value0: sig.Prototype()}
        }
    }
    return base.None[FuncInfo]{}
}

func MethodSig(receiverType string, name string, argCount int) base.Option[FuncInfo] {
    if sigs, ok := methodSigs[receiverType]; ok {
        if sig, ok := sigs[name]; ok {
            if value, ok := sig.Exact(argCount); ok {
                return base.Some[FuncInfo]{Value0: value}
            }
            return base.None[FuncInfo]{}
        }
    }
    return base.None[FuncInfo]{}
}

func InterfaceMethods(interfaceType string) []FuncInfo {
    if methods, ok := interfaceMethods[interfaceType]; ok {
        return methods
    }
    return []FuncInfo{}
}

func NamedUnderlyingType(typeName string) string {
    if underlying, ok := namedUnderlyingTypes[typeName]; ok {
        return underlying
    }
    return ""
}

type generatedFuncSig struct {
    Name             string
    FixedParamNames  []string
    FixedParamTypes  []string
    Variadic         bool
    VariadicName     string
    VariadicElemType string
    ResultTypes      []string
}

func (sig generatedFuncSig) Prototype() FuncInfo {
    return FuncInfo{Name: sig.Name, TypeParams: []string{}, ParamNames: sig.FixedParamNames, ParamTypes: sig.FixedParamTypes, ResultTypes: sig.ResultTypes}
}

func (sig generatedFuncSig) Exact(argCount int) (FuncInfo, bool) {
    if sig.Variadic {
        if argCount < len(sig.FixedParamTypes) {
            return FuncInfo{}, false
        }
        return VariadicFuncInfo(sig.Name, sig.FixedParamNames, sig.FixedParamTypes, sig.VariadicElemType, argCount, sig.ResultTypes), true
    }
    if argCount != len(sig.FixedParamTypes) {
        return FuncInfo{}, false
    }
    return sig.Prototype(), true
}
